sql:
SELECT DISTINCT make
FROM vehicles
ORDER BY make;

SELECT v.license_plate
FROM vehicles v
JOIN accidents a ON v.vehicle_id = a.vehicle_id;

SELECT vehicle_id, MAX(registration_date) AS latest_registration_date
FROM vehicle_registration
GROUP BY vehicle_id;

SELECT MAX(date_time) AS most_recent_date_time
FROM gps_data
WHERE vehicle_id = 1;

SELECT COUNT(*) AS maintenance_count
FROM vehicle_maintenance
WHERE vehicle_id = 123;

SELECT make || ' ' || model AS vehicle_make_model
FROM vehicles
ORDER BY vehicle_make_model;
